$(document).ready(function () {

    var baseUrl = window.location.origin;
    let retrive_data = baseUrl + '/ca_report_ako_jama_ajax';

    let grandTotals = {
    Akki: 0,
    Kai: 0,
    Oil: 0
};

    var table = $('#ca-report-ako-jama').DataTable({
        processing: true,
        serverSide: true,
        destroy: true,
        dom: 'Bfrtip',

        buttons: [
            // ✅ EXCEL EXPORT
            {
                extend: 'excelHtml5',
                text: 'Export to Excel',
                filename: 'CA_Report_AKO_Jama',

                customize: function (xlsx) {
                    var sheet = xlsx.xl.worksheets['sheet1.xml'];

                    // Title
                    $('c[r=A1] t', sheet).text('AKO Jama Report');

                    // Last row
                    var lastRow = $('row', sheet).length + 1;

                    // ✅ Grand Total Row (Akki, Kai, Oil)
                    var grandTotalRow =
                        `<row r="${lastRow}">
                            <c t="inlineStr" r="A${lastRow}">
                                <is><t>Grand Total</t></is>
                            </c>
                            <c t="n" r="C${lastRow}">
                                <v>${grandTotals.Akki}</v>
                            </c>
                            <c t="n" r="D${lastRow}">
                                <v>${grandTotals.Kai}</v>
                            </c>
                            <c t="n" r="E${lastRow}">
                                <v>${grandTotals.Oil}</v>
                            </c>
                        </row>`;

                    sheet.childNodes[0].childNodes[1].innerHTML += grandTotalRow;
                }
            },

            // ✅ PDF EXPORT
            {
                extend: 'pdf',
                text: 'Export to PDF',
                filename: 'CA_Report_AKO_Jama',

                customize: function (doc) {

                    // Title
                    doc.content.splice(0, 0, {
                        text: 'AKO Jama Report',
                        fontSize: 14,
                        bold: true,
                        margin: [0, 0, 0, 10]
                    });

                     // ✅ Grand Total Row
                    doc.content.push({
                        text: `Grand Total  |  Akki: ${grandTotals.Akki}  |  Kai: ${grandTotals.Kai}  |  Oil: ${grandTotals.Oil}`,
                        margin: [0, 10, 0, 0],
                        bold: true
                    });
                }
            }
        ],

        ajax: {
            url: retrive_data,
            data: function (d) {
                d.financial_year = $('.financial_year').val();
            },
            dataSrc: function (json) {
                 // ✅ store totals
                if (json.grand_total) {
                    grandTotals.Akki = json.grand_total.Akki;
                    grandTotals.Kai  = json.grand_total.Kai;
                    grandTotals.Oil  = json.grand_total.Oil;
                }

                return json.data;
            }
        },

        columns: [
            {
                data: null,
                render: function (data, type, row, meta) {
                    return meta.row + 1;
                }
            },
            { data: "subcategory_name" },
            { data: "Akki" },
            { data: "Kai" },
            { data: "Oil" },
            
        ],
         // ✅ ADD THIS
    footerCallback: function (row, data, start, end, display) {
        var api = this.api();

        // Get grand total from backend
        var json = api.ajax.json();

        if (json && json.grand_total) {
            $(api.column(2).footer()).html(json.grand_total.Akki);
            $(api.column(3).footer()).html(json.grand_total.Kai);
            $(api.column(4).footer()).html(json.grand_total.Oil);
        }
    }
    });

    // Reload on filter
    $('.submit_purchase_report').click(function () {
        table.ajax.reload();
    });

});